// avio_read_callback.c - قراءة من مصدر مخصص عبر callback
#include <libavformat/avformat.h>
#include <libavformat/avio.h>
#include <string.h>

// هذه الدالة تُستدعى تلقائيًا عندما يحتاج FFmpeg لقراءة بيانات
static int read_callback(void *opaque, uint8_t *buf, int buf_size) {
    // opaque هو المؤشر الذي تمرره لـ avio_alloc_context
    FILE *fp = (FILE *)opaque;
    return (int)fread(buf, 1, buf_size, fp);
}

int main(int argc, char **argv) {
    if (argc < 2) {
        fprintf(stderr, "الاستخدام: %s <ملف>\n", argv[0]);
        return 1;
    }

    FILE *fp = fopen(argv[1], "rb");
    if (!fp) {
        fprintf(stderr, "فشل فتح الملف\n");
        return 1;
    }

    // إنشاء AVFormatContext مع مصدر مخصص
    AVFormatContext *fmt_ctx = avformat_alloc_context();
    AVIOContext *avio = avio_alloc_context(
        NULL, 4096, 0,
        fp,              // opaque: مؤشر الملف
        read_callback,   // دالة القراءة
        NULL,            // write_packet
        NULL             // seek
    );
    fmt_ctx->pb = avio;
    fmt_ctx->flags |= AVFMT_FLAG_CUSTOM_IO;

    // الآن FFmpeg يقرأ من callback بدل ملف مباشر
    if (avformat_open_input(&fmt_ctx, NULL, NULL, NULL) < 0) {
        fprintf(stderr, "فشل فتح المدخل\n");
        return 1;
    }

    avformat_find_stream_info(fmt_ctx, NULL);
    printf("نجح: فتح ملف عبر callback\n");

    avformat_close_input(&fmt_ctx);
    fclose(fp);
    avio_context_free(&avio);
    return 0;
}

