#include <libavformat/avio.h>

static int read_packet(void *opaque, uint8_t *buf, int buf_size) {
    // قراءة buf_size بايت من مصدرك المخصص
    // مثلاً: من ذاكرة، شبكة، أو ملف مشفّر
    return custom_read(opaque, buf, buf_size);
}

int main() {
    AVFormatContext *fmt_ctx = avformat_alloc_context();
    AVIOContext *avio = avio_alloc_context(
        NULL, 4096, 0, NULL, read_packet, NULL, NULL
    );
    fmt_ctx->pb = avio;
    fmt_ctx->flags |= AVFMT_FLAG_CUSTOM_IO;
    avformat_open_input(&fmt_ctx, NULL, NULL, NULL);
    // الآن fmt_ctx يقرأ من callback بدل ملف
